#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
#define Clear(a) memset(a,0,sizeof(a))
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e3+10,M=2e6+10;
struct Graph
{
	int head[N],des[M],nxt[M],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];des[cnt]=y;head[x]=cnt;}
	inline void Init(){Clear(head);cnt=1;}
}a;
int n,m,cnt,dep;bool flag[N],edg[N][N];
vector<int> dcc[N];
int stk[N],dfn[N],low[N],f[N],h[N],col[N],top;
void tarjan(int u)
{
	stk[++top]=u;dfn[u]=low[u]=++dep;
	grep(a,u,i)
	{
		int v=a.des[i];if(!dfn[v])
		{
			tarjan(v);low[u]=min(low[u],low[v]);
			if(dfn[u]<=low[v])
			{
				dcc[++cnt].clear();int z;
				do{dcc[cnt].push_back(z=stk[top--]);}while(z^v);
				dcc[cnt].push_back(u);
			}
		}
		else low[u]=min(low[u],dfn[v]);
	}
}
bool dfs(int u,int fa)
{
//	printf("%d\n",u);
	grep(a,u,i)
	{
		int v=a.des[i];if(f[v]^fa)continue;if(col[v]==col[u])return 0;
		if(col[v])continue;col[v]=col[u]^1;if(!dfs(v,fa))return 0;
	}return 1;
}
int main()
{
	//freopen("ddtt.txt","r",stdin);
//	freopen("ggq.txt","w",stdout);
	while(n=read(),m=read())
	{
		Clear(flag);Clear(edg);Clear(dfn);Clear(low);Clear(f);cnt=0;a.Init();
		rep(1,m,i){int x=read(),y=read();edg[x][y]=edg[y][x]=1;}
		rep(1,n,i)rep(1,n,j)if(i^j&&edg[i][j])a.ins(i,j);
		rep(1,n,i)if(!dfn[i]){if(!a.head[i]){dcc[++cnt].clear();dcc[cnt].push_back(i);}else tarjan(i);}
//		rep(1,n,i)grep(a,i,j)printf("%d' %d'\n",i,a.des[j]);
//		rep(1,cnt,i){printf("%d: ",i);int sz=dcc[i].size();rep(0,sz-1,j)printf("%d ",dcc[i][j]);puts("");}
		rep(1,cnt,i)
		{
			Clear(col);col[dcc[i][0]]=2;int sz=dcc[i].size();
			rep(0,sz-1,j)f[dcc[i][j]]=i;if(!dfs(dcc[i][0],i))rep(0,sz-1,j)flag[dcc[i][j]]=1;
		}
//		rep(1,n,i)printf("%d ",f[i]);puts("");
		int ans=n;rep(1,n,i){ans-=flag[i];}printf("%d\n",ans);
	}
}
